import { RE2Flags } from './RE2Flags.js'
import { Utils } from './Utils.js'
import { Unicode } from './Unicode.js'
/**
 * A single instruction in the regular expression virtual machine.
 *
 * @see http://swtch.com/~rsc/regexp/regexp2.html
 */
class Inst {
  static ALT = 1
  static ALT_MATCH = 2
  static CAPTURE = 3
  static EMPTY_WIDTH = 4
  static FAIL = 5
  static MATCH = 6
  static NOP = 7
  static RUNE = 8
  static RUNE1 = 9
  static RUNE_ANY = 10
  static RUNE_ANY_NOT_NL = 11
  static LB_WRITE = 12
  static LB_CHECK = 13

  static isRuneOp(op) {
    return Inst.RUNE <= op && op <= Inst.RUNE_ANY_NOT_NL
  }

  // Returns an RE2 expression matching exactly |runes|.
  static escapeRunes(runes) {
    let out = '"'
    for (let rune of runes) {
      out += Utils.escapeRune(rune)
    }
    out += '"'
    return out
  }

  constructor(op) {
    this.op = op
    this.out = 0 // all but MATCH, FAIL
    this.arg = 0 // ALT, ALT_MATCH, CAPTURE, EMPTY_WIDTH
    // length==1 => exact match
    // otherwise a list of [lo,hi] pairs.  hi is *inclusive*.
    this.runes = []
  }

  // MatchRune returns true if the instruction matches (and consumes) r.
  // It should only be called when op == InstRune.
  matchRune(r) {
    // Special case: single-rune slice is from literal string, not char
    // class.
    if (this.runes.length === 1) {
      const r0 = this.runes[0]
      // If this pattern is case-insensitive, apply Unicode case folding to compare the two runes.
      // Note that this may result in a case-folding loop when executed,
      // so attempt to reduce the chance of that occurring
      // by performing case folding on |r0| from the pattern rather than |r| from the input.
      if ((this.arg & RE2Flags.FOLD_CASE) !== 0) {
        return Unicode.equalsIgnoreCase(r0, r)
      }
      return r === r0
    }

    const len = this.runes.length
    if (len === 0) return false

    // If the array is exactly 2, 4, 6, or 8 items, DO NOT fall through to binary search
    if (len === 2 || len === 4 || len === 6 || len === 8) {
      for (let j = 0; j < len; j += 2) {
        if (r < this.runes[j]) {
          return false
        }
        if (r <= this.runes[j + 1]) {
          return true
        }
      }
      return false // Stop here
    }

    // Branchless Binary Search (Lower Bound)
    // Compiles to optimal conditional move (cmov) machine code, preventing
    // branch mispredictions on large, chaotic Unicode arrays
    let base = 0
    let n = len >> 1
    while (n > 1) {
      const half = n >> 1
      base += this.runes[(base + half) << 1] <= r ? half : 0
      n -= half
    }
    base += this.runes[base << 1] <= r ? 1 : 0

    const m = base - 1
    return m >= 0 && r <= this.runes[(m << 1) | 1]
  }

  // matchRunePos checks whether the instruction matches (and consumes) r.
  // If so, it returns the index of the matching rune pair.
  // If not, it returns -1.
  matchRunePos(r) {
    if (this.runes.length === 1) {
      const r0 = this.runes[0]
      if ((this.arg & RE2Flags.FOLD_CASE) !== 0) {
        return Unicode.equalsIgnoreCase(r0, r) ? 0 : -1
      }
      return r === r0 ? 0 : -1
    }

    const len = this.runes.length
    if (len === 0) return -1

    if (len === 2 || len === 4 || len === 6 || len === 8) {
      for (let j = 0; j < len; j += 2) {
        if (r < this.runes[j]) return -1
        if (r <= this.runes[j + 1]) return Math.floor(j / 2)
      }
      return -1
    }

    // Branchless Binary Search (Lower Bound)
    let base = 0
    let n = len >> 1
    while (n > 1) {
      const half = n >> 1
      base += this.runes[(base + half) << 1] <= r ? half : 0
      n -= half
    }
    base += this.runes[base << 1] <= r ? 1 : 0

    const m = base - 1
    return m >= 0 && r <= this.runes[(m << 1) | 1] ? m : -1
  }
  /**
   *
   * @returns {string}
   */
  toString() {
    switch (this.op) {
      case Inst.ALT:
        return `alt -> ${this.out}, ${this.arg}`
      case Inst.ALT_MATCH:
        return `altmatch -> ${this.out}, ${this.arg}`
      case Inst.CAPTURE:
        return `cap ${this.arg} -> ${this.out}`
      case Inst.EMPTY_WIDTH:
        return `empty ${this.arg} -> ${this.out}`
      case Inst.MATCH:
        return `match${this.arg !== 0 ? ` ${this.arg}` : ''}`
      case Inst.FAIL:
        return 'fail'
      case Inst.NOP:
        return `nop -> ${this.out}`
      case Inst.LB_WRITE:
        return `lbwrite ${this.lb} -> ${this.out}`
      case Inst.LB_CHECK:
        return `lbcheck ${this.lb} -> ${this.out}, ${this.arg}`
      case Inst.RUNE:
        if (this.runes === null) {
          return 'rune <null>'
        }
        return [
          'rune ',
          Inst.escapeRunes(this.runes),
          (this.arg & RE2Flags.FOLD_CASE) !== 0 ? '/i' : '',
          ' -> ',
          this.out
        ].join('')
      case Inst.RUNE1:
        return `rune1 ${Inst.escapeRunes(this.runes)} -> ${this.out}`
      case Inst.RUNE_ANY:
        return `any -> ${this.out}`
      case Inst.RUNE_ANY_NOT_NL:
        return `anynotnl -> ${this.out}`
      default:
        throw new Error('unhandled case in Inst.toString')
    }
  }
}

export { Inst }
